  /// Valid for PRESS, DRAG, AUTOSCROLL_TICK, and DEEP_PRESS.
  GHOSTTY_SELECTION_GESTURE_EVENT_OPT_WORD_BOUNDARY_CODEPOINTS(5),

  /// Selection behavior table: GhosttySelectionGestureBehaviors*.
