  /// The raw cell value (GhosttyCell).
  GHOSTTY_RENDER_STATE_ROW_CELLS_DATA_RAW(1),

  /// The style for the current cell (GhosttyStyle).
  GHOSTTY_RENDER_STATE_ROW_CELLS_DATA_STYLE(2),

